const Question = require('../models/Question');
const { errorHandler } = require('../utils/helpers');

const getQuestions = async (req, res) => {
  try {
    const { page = 1, limit = 10, category, difficulty, type, search } = req.query;

    const query = {};

    if (category) query.category = category;
    if (difficulty) query.difficulty = difficulty;
    if (type) query.type = type;
    if (search) {
      query.$or = [
        { title: { $regex: search, $options: 'i' } },
        { description: { $regex: search, $options: 'i' } }
      ];
    }

    const questions = await Question.find(query)
      .populate('createdBy', 'username')
      .sort({ createdAt: -1 })
      .limit(limit * 1)
      .skip((page - 1) * limit);

    const total = await Question.countDocuments(query);

    res.json({
      questions,
      totalPages: Math.ceil(total / limit),
      currentPage: page,
      total
    });
  } catch (error) {
    errorHandler(res, error);
  }
};

const getQuestionById = async (req, res) => {
  try {
    const question = await Question.findById(req.params.id)
      .populate('createdBy', 'username');

    if (!question) {
      return res.status(404).json({ message: '题目不存在' });
    }

    res.json(question);
  } catch (error) {
    errorHandler(res, error);
  }
};

const createQuestion = async (req, res) => {
  try {
    const { title, description, type, options, correctAnswer, explanation, difficulty, category, tags } = req.body;

    const question = new Question({
      title,
      description,
      type,
      options,
      correctAnswer,
      explanation,
      difficulty,
      category,
      tags,
      createdBy: req.user.id
    });

    await question.save();
    await question.populate('createdBy', 'username');

    res.status(201).json({
      message: '题目创建成功',
      question
    });
  } catch (error) {
    errorHandler(res, error);
  }
};

const updateQuestion = async (req, res) => {
  try {
    const { title, description, type, options, correctAnswer, explanation, difficulty, category, tags, isActive } = req.body;

    const question = await Question.findById(req.params.id);

    if (!question) {
      return res.status(404).json({ message: '题目不存在' });
    }

    const updatedQuestion = await Question.findByIdAndUpdate(
      req.params.id,
      { title, description, type, options, correctAnswer, explanation, difficulty, category, tags, isActive },
      { new: true }
    ).populate('createdBy', 'username');

    res.json({
      message: '题目更新成功',
      question: updatedQuestion
    });
  } catch (error) {
    errorHandler(res, error);
  }
};

const deleteQuestion = async (req, res) => {
  try {
    const question = await Question.findById(req.params.id);

    if (!question) {
      return res.status(404).json({ message: '题目不存在' });
    }

    await Question.findByIdAndDelete(req.params.id);

    res.json({ message: '题目删除成功' });
  } catch (error) {
    errorHandler(res, error);
  }
};

const getCategories = async (req, res) => {
  try {
    const categories = await Question.distinct('category');
    res.json(categories);
  } catch (error) {
    errorHandler(res, error);
  }
};

module.exports = {
  getQuestions,
  getQuestionById,
  createQuestion,
  updateQuestion,
  deleteQuestion,
  getCategories
};

