  try {
    const user = await User.findById(req.params.id).select('-password');

    if (!user) {
      return res.status(404).json({ message: '用户不存在' });
    }

    const stats = await Record.aggregate([
      { $match: { user: user._id } },
      {
        $group: {
          _id: null,
          totalAttempts: { $sum: 1 },
          correctAnswers: { $sum: { $cond: ['$isCorrect', 1, 0] } },
          averageTime: { $avg: '$timeSpent' }
