const Record = require('../models/Record');
const User = require('../models/User');
const Question = require('../models/Question');
const { errorHandler } = require('../utils/helpers');

const getRecords = async (req, res) => {
  try {
    const { page = 1, limit = 10, userId, questionId, isCorrect, startDate, endDate } = req.query;

    const query = {};

    if (userId) query.user = userId;
    if (questionId) query.question = questionId;
    if (isCorrect !== undefined) query.isCorrect = isCorrect === 'true';
    if (startDate || endDate) {
      query.createdAt = {};
      if (startDate) query.createdAt.$gte = new Date(startDate);
      if (endDate) query.createdAt.$lte = new Date(endDate);
    }

    const records = await Record.find(query)
      .populate('user', 'username email')
      .populate('question', 'title category difficulty')
      .sort({ createdAt: -1 })
      .limit(limit * 1)
      .skip((page - 1) * limit);

    const total = await Record.countDocuments(query);

    res.json({
      records,
      totalPages: Math.ceil(total / limit),
      currentPage: page,
      total
    });
  } catch (error) {
    errorHandler(res, error);
  }
};

const getRecordById = async (req, res) => {
  try {
    const record = await Record.findById(req.params.id)
      .populate('user', 'username email')
      .populate('question');

    if (!record) {
      return res.status(404).json({ message: '答题记录不存在' });
    }

    res.json(record);
  } catch (error) {
    errorHandler(res, error);
  }
};

const createRecord = async (req, res) => {
  try {
    const { questionId, userAnswer, timeSpent, quizSession } = req.body;

    const question = await Question.findById(questionId);
    if (!question) {
      return res.status(404).json({ message: '题目不存在' });
    }

    const isCorrect = userAnswer === question.correctAnswer;

    const record = new Record({
      user: req.user.id,
      question: questionId,
      userAnswer,
      isCorrect,
      timeSpent: timeSpent || 0,
      quizSession: quizSession || ''
    });

    await record.save();
    await record.populate(['user', 'question']);

    res.status(201).json({
      message: '答题记录创建成功',
      record
    });
  } catch (error) {
    errorHandler(res, error);
  }
};

const getRecordsByUser = async (req, res) => {
  try {
    const { page = 1, limit = 10 } = req.query;

    const records = await Record.find({ user: req.params.userId })
      .populate('question', 'title category difficulty')
      .sort({ createdAt: -1 })
      .limit(limit * 1)
      .skip((page - 1) * limit);

    const total = await Record.countDocuments({ user: req.params.userId });

    const stats = await Record.aggregate([
      { $match: { user: mongoose.Types.ObjectId(req.params.userId) } },
      {
        $group: {
          _id: null,
          totalAttempts: { $sum: 1 },
          correctAnswers: { $sum: { $cond: ['$isCorrect', 1, 0] } },
          averageTime: { $avg: '$timeSpent' }
        }
      }
    ]);

    res.json({
      records,
      stats: stats[0] || { totalAttempts: 0, correctAnswers: 0, averageTime: 0 },
      totalPages: Math.ceil(total / limit),
      currentPage: page,
      total
    });
  } catch (error) {
    errorHandler(res, error);
  }
};

const getDashboardStats = async (req, res) => {
  try {
    const totalRecords = await Record.countDocuments();
    const correctRecords = await Record.countDocuments({ isCorrect: true });

    const recentRecords = await Record.find()
      .populate('user', 'username')
      .populate('question', 'title')
      .sort({ createdAt: -1 })
      .limit(10);

    const topUsers = await Record.aggregate([
      {
        $group: {
          _id: '$user',
          totalAttempts: { $sum: 1 },
          correctAnswers: { $sum: { $cond: ['$isCorrect', 1, 0] } }
        }
      },
      {
        $lookup: {
          from: 'users',
          localField: '_id',
          foreignField: '_id',
          as: 'userInfo'
        }
      },
      {
        $unwind: '$userInfo'
      },
      {
        $project: {
          username: '$userInfo.username',
          email: '$userInfo.email',
          totalAttempts: 1,
          correctAnswers: 1,
          accuracy: { $divide: ['$correctAnswers', '$totalAttempts'] }
        }
      },
      { $sort: { totalAttempts: -1 } },
      { $limit: 5 }
    ]);

    res.json({
      totalRecords,
      correctRecords,
      accuracyRate: totalRecords > 0 ? (correctRecords / totalRecords * 100).toFixed(2) : 0,
      recentRecords,
      topUsers
    });
  } catch (error) {
    errorHandler(res, error);
  }
};

module.exports = {
  getRecords,
  getRecordById,
  createRecord,
  getRecordsByUser,
  getDashboardStats
};

const express = require('express');
const { body } = require('express-validator');
const { adminAuth, auth } = require('../middleware/auth');
const {
  getRecords,
  getRecordById,
  createRecord,
  getRecordsByUser,
  getDashboardStats
} = require('../controllers/recordController');

const router = express.Router();

router.get('/', adminAuth, getRecords);
router.get('/dashboard', adminAuth, getDashboardStats);
router.get('/user/:userId', adminAuth, getRecordsByUser);
router.get('/:id', adminAuth, getRecordById);
router.post('/', auth, [
  body('questionId').notEmpty().withMessage('题目ID不能为空'),
  body('userAnswer').notEmpty().withMessage('用户答案不能为空')
], createRecord);

module.exports = router;

